import React from "react";
import ReactDOM from "react-dom";
import "./nav.css";

function Nav() {
  const [open, setOpen] = React.useState(false);
  function Modal() {
    if (!setOpen) {
      isOpen = () => {
        return <div className="pushMenu"></div>;
      };
    } else {
      return <div className="pushMenu"></div>;
    }
  }
  return <div onClick={Modal} className="gg-menu-grid-o"></div>;
}

export default Nav;

